import XCTest
@testable import SwiftSlash
@testable import ClibSwiftSlash

func helloWorld(_ buff:UnsafePointer<UInt8>, _ buffSize:size_t, _ isClosed:Bool, _ usrPtr:UnsafeMutableRawPointer?) {
	let getData = Data(bytes:buff, count:buffSize)
	let asString = String(data:getData, encoding:.utf8)
	print("\(asString!)")
//	print("\(asString!)");
//	usrPtr!.assumingMemoryBound(to:[String].self).pointee.append(asString)
}

func helloWriter(_ isClosed:Bool, _ usrPtr:UnsafeMutableRawPointer?) {
	print("lets ride");
}

final class SwiftSlashInternalTests:XCTestCase {
	func testFDResourceUtilization() {
		var getUsed:Double = 0;
		var getTotal:Double = 0;
		guard getfdlimit(&getUsed, &getTotal) == 0 else {
			XCTFail();
			return
		}
		_ = open("/dev/null", 0);
		var newUsed:Double = 0;
		var newTotal:Double = 0;
		guard getfdlimit(&newUsed, &newTotal) == 0 else {
			XCTFail();
			return
		}
		XCTAssert((getUsed + 1) == newUsed)
	}
	
